// ─────────────────────────────────────────────────────────────────
// Receives HTML from TWO pages of news.kenyagazette.co.ke:
//   1. /category/gazette-notices/  — full gazette notices listing
//   2. /?s=campaign+finance        — site search results
// Scans TITLE TEXT of every <a> and <h1>-<h4> on both pages.
// Only notices whose title contains campaign finance keywords are kept.
// ─────────────────────────────────────────────────────────────────

// Combine HTML from all input items (gazette page + search page)
const combinedHtml = $input.all().map(item =>
  item.json.body || item.json.data || ''
).join('\n');

const html = combinedHtml;

// Campaign-finance title keywords — matched against notice TITLES only
const TITLE_KW = [
  'campaign finance',
  'campaign fund',
  'campaign financing',
  'election fund',
  'election finance',
  'election financing',
  'spending limit',
  'spending return',
  'expenditure return',
  'expenditure report',
  'donor disclosure',
  'donor declaration',
  'contribution return',
  'contribution report',
  'political party fund',
  'party financing',
  'funding disclosure',
  'funding return',
  'campaign account',
  'election expenses',
  'campaign spending'
];

function titleMatchesCampaignFinance(title) {
  const t = title.toLowerCase();
  return TITLE_KW.some(kw => t.includes(kw));
}

function toAbsoluteUrl(href) {
  if (!href) return null;
  href = href.trim();
  if (href.startsWith('http://') || href.startsWith('https://')) return href;
  return `https://news.kenyagazette.co.ke${href.startsWith('/') ? '' : '/'}${href}`;
}

const results = [];

// ── 1. Scan every <a> tag — check its visible title text ──
const anchorRegex = /<a[^>]+href=["']([^"']+)["'][^>]*>([\s\S]*?)<\/a>/gi;
let m;
while ((m = anchorRegex.exec(html)) !== null) {
  const href = m[1];
  const title = m[2].replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
  if (title.length < 5) continue;
  if (titleMatchesCampaignFinance(title)) {
    const url = toAbsoluteUrl(href);
    if (url) results.push({ url, title, isPdf: href.toLowerCase().includes('.pdf') });
  }
}

// ── 2. Scan <h1>–<h4> headings — grab nearest link after each match ──
const headingRegex = /<h[1-4][^>]*>([\s\S]*?)<\/h[1-4]>/gi;
while ((m = headingRegex.exec(html)) !== null) {
  const headingText = m[1].replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
  if (!titleMatchesCampaignFinance(headingText)) continue;
  const after = html.substring(m.index, Math.min(html.length, m.index + 800));
  const nearLink = /<a[^>]+href=["']([^"']+)["']/i.exec(after);
  if (nearLink) {
    const url = toAbsoluteUrl(nearLink[1]);
    if (url && !results.some(r => r.url === url)) {
      results.push({ url, title: headingText, isPdf: nearLink[1].toLowerCase().includes('.pdf') });
    }
  }
}

// Deduplicate by URL and cap at 10 per cycle
const seen = new Set();
const unique = results.filter(r => {
  if (seen.has(r.url)) return false;
  seen.add(r.url);
  return true;
}).slice(0, 10);

if (unique.length === 0) {
  return [{
    json: {
      _no_pdfs: true,
      message: 'No campaign financing notices found in gazette titles this cycle',
      total_anchors_scanned: (html.match(/<a /gi) || []).length
    }
  }];
}

return unique.map(item => ({
  json: {
    pdf_url: item.url,
    notice_title: item.title,
    is_direct_pdf: item.isPdf,
    source_name: `Kenya Gazette - ${item.title.substring(0, 100)}`,
    source_type: 'Kenya Gazette - Campaign Finance'
  }
}));

const text = $input.first().json.data || $input.first().json.body || '';
const parentItem = $('Found PDFs?').first().json;
const sourceName = parentItem.source_name || parentItem.notice_title || 'Kenya Gazette Campaign Finance Notice';
const sourceType = parentItem.source_type || 'Kenya Gazette - Campaign Finance';
const pdfUrl = parentItem.pdf_url || '';
const noticeTitle = parentItem.notice_title || sourceName;

const words = String(text).split(/\s+/);
const chunkSize = 500;
const overlap = 50;
const chunks = [];

for (let i = 0; i < words.length; i += chunkSize - overlap) {
  const chunk = words.slice(i, i + chunkSize).join(' ');
  if (chunk.trim().length > 20) {
    chunks.push({
      json: {
        source_name: sourceName,
        source_type: sourceType,
        source_url: pdfUrl,
        notice_title: noticeTitle,
        chunk_index: chunks.length,
        content: chunk.trim()
      }
    });
  }
}

if (chunks.length === 0) {
  return [{ json: { _empty: true, source_name: sourceName, notice_title: noticeTitle, message: 'No text content extracted from gazette document' } }];
}

return chunks;

const chunkData = $('Has Chunks?').first().json;
const embedding = $input.first().json.output || [];

return [{
  json: {
    source_name: chunkData.source_name,
    source_type: chunkData.source_type,
    source_url: chunkData.source_url || '',
    notice_title: chunkData.notice_title || '',
    chunk_index: chunkData.chunk_index,
    content: chunkData.content,
    embedding: embedding
  }
}];
